// Queen Episodes — Episode Management & JSONL Persistence
// φ² + 1/φ² = 3 | TRINITY

const std = @import("std");

/// Import types from all Lotus Cycle stages
pub const Context = @import("observe.zig").Context;
pub const Evaluation = @import("evaluate.zig").Evaluation;
pub const Plan = @import("plan.zig").Plan;
pub const Result = @import("act.zig").Result;
pub const Outcome = @import("act.zig").Outcome;

/// Episode source
pub const Source = enum {
    /// Generated by Lotus Cycle
    lotus_cycle,
    /// External command/trigger
    external,
    /// Scheduled task
    scheduled,
    /// Recalled from experience
    experience_recall,
};

/// Episode action type
pub const Action = union(enum) {
    scale_up: struct {
        key: []const u8,
        quality_score: f64,
    },
    scale_down: struct {
        key: []const u8,
        quality_score: f64,
    },
    trigger: struct {
        key: []const u8,
    },
    set: struct {
        key: []const u8,
        value: union {
            bool: bool,
            f64: f64,
        },
    },
    wait: void,
};

/// Complete episode record
pub const Episode = struct {
    /// Unique episode ID (timestamp-based)
    id: u64,
    /// Unix timestamp (nanos)
    timestamp: u64,
    /// Episode source
    source: Source,
    /// Context before action
    context: Context,
    /// Action taken
    action: Action,
    /// Result of action
    result: Result,
    /// Derived outcome
    outcome: Outcome,
};

/// Load options
pub const LoadOptions = struct {
    /// Maximum episodes to load (0 = all)
    limit: u32 = 0,
    /// Filter by source type
    source_filter: ?Source = null,
    /// Filter by outcome
    outcome_filter: ?Outcome = null,
};

/// Record episode from Lotus Cycle result
pub fn recordEpisode(allocator: std.mem.Allocator, context: Context, plan: Plan, result: Result, outcome: Outcome) !Episode {
    const now_ns = std.time.nanoTimestamp();

    // Build action struct based on plan
    const action = switch (plan.action) {
        .scale_up => Action{
            .scale_up = .{
                .key = plan.key,
                .quality_score = plan.quality_score,
            },
        },
        .scale_down => Action{
            .scale_down = .{
                .key = plan.key,
                .quality_score = plan.quality_score,
            },
        },
        .trigger => Action{
            .trigger = .{
                .key = plan.key,
            },
        },
        .wait => Action{ .wait = {} },
    };

    return Episode{
        .id = now_ns,
        .timestamp = now_ns,
        .source = .lotus_cycle,
        .context = context,
        .action = action,
        .result = result,
        .outcome = outcome,
    };
}

/// Append episode to JSONL file
pub fn appendEpisode(episode: Episode, allocator: std.mem.Allocator) !void {
    // Ensure directory exists
    const episodes_dir = ".trinity/queen";
    std.fs.cwd().makePath(episodes_dir) catch |err| {
        if (err != error.PathAlreadyExists) return err;
    };

    const file_path = try std.fmt.allocPrint(allocator, "{s}/episodes.jsonl", .{episodes_dir});
    defer allocator.free(file_path);

    const file = try std.fs.cwd().openFile(file_path, .{ .mode = .write });
    defer file.close();

    // Seek to end for append
    try file.seekFromEnd(0);

    // Serialize episode to JSONL
    const json = try std.json.stringifyAlloc(allocator, episode, .{ .whitespace = .minified });
    defer allocator.free(json);

    // Write as JSON line
    const line = try std.fmt.allocPrint(allocator, "{s}\n", .{json});
    defer allocator.free(line);

    try file.writeAll(line);
}

/// Load episodes from JSONL file with optional filtering
pub fn loadEpisodes(allocator: std.mem.Allocator, options: LoadOptions) ![]Episode {
    const file_path = ".trinity/queen/episodes.jsonl";

    const file = std.fs.cwd().openFile(file_path, .{}) catch {
        // File doesn't exist yet
        return try allocator.alloc(Episode, 0);
    };
    defer file.close();

    // Read all file contents - Zig 0.15 requires max_bytes parameter
    const contents = file.readToEndAlloc(allocator, 1024 * 1024) catch |_| {
        return try allocator.alloc(Episode, 0);
    };
    defer allocator.free(contents);

    var episodes = std.ArrayList(Episode).init(allocator);
    defer episodes.deinit();

    // Parse each line (JSONL format)
    var line_iter = std.mem.splitScalar(u8, contents, '\n');
    var loaded: u32 = 0;

    while (line_iter.next()) |line| {
        if (line.len == 0) {
            // Skip empty lines
            if (true) continue;
        }

        const episode = std.json.parseFromSlice(Episode, line) catch _ {
            // Skip invalid lines
            if (true) continue;
        };

        // Apply source filter
        if (options.source_filter) |filter| {
            if (episode.source != filter) { { continue; } }
        }

        // Apply outcome filter
        if (options.outcome_filter) |filter| {
            if (episode.outcome != filter) { continue; }
        }

        try episodes.append(episode);
        loaded += 1;

        // Check limit
        if (options.limit > 0 and loaded >= options.limit) {
            break;
        }
    }

    return try episodes.toOwnedSlice();
}

/// Get last episode from episodes file
pub fn getLastEpisode(allocator: std.mem.Allocator) ?Episode {
    const episodes = try loadEpisodes(allocator, .{ .limit = 1 });
    defer allocator.free(episodes);

    if (episodes.len == 0) return null;
    return episodes[episodes.len - 1];
}

/// Episode statistics
pub const EpisodeStats = struct {
    total: u32,
    by_source: [4]u32, // lotus_cycle, external, scheduled, experience_recall
    by_outcome: [5]u32, // success, partial, failure_learned, failure_unknown, blocked
    last_24h: u32,
};

/// Calculate episode statistics
pub fn getEpisodeStats(allocator: std.mem.Allocator) !EpisodeStats {
    const episodes = try loadEpisodes(allocator, .{});
    defer allocator.free(episodes);

    const now_ns = std.time.nanoTimestamp();
    const day_ns: u64 = 24 * 60 * 60 * 1_000_000_000;

    var stats = EpisodeStats{
        .total = @intCast(episodes.len),
        .by_source = [_]u32{0} ** 4,
        .by_outcome = [_]u32{0} ** 5,
        .last_24h = 0,
    };

    for (episodes) |ep| {
        // Count by source
        const source_idx: u3 = @intFromEnum(ep.source);
        stats.by_source[source_idx] += 1;

        // Count by outcome
        const outcome_idx: u3 = @intFromEnum(ep.outcome);
        stats.by_outcome[outcome_idx] += 1;

        // Count last 24h
        if (now_ns - ep.timestamp < day_ns) {
            stats.last_24h += 1;
        }
    }

    return stats;
}

test "episodes: recordEpisode creates valid episode" {
    const allocator = std.testing.allocator;

    const context = Context{
        .timestamp_ns = 1234567890,
        .policy = .{},
        .senses = .{},
        .active_issues = try allocator.alloc(u64, 0),
    };
    defer allocator.free(context.active_issues);

    const plan = Plan{
        .action = .scale_up,
        .key = "kill_threshold",
        .quality_score = 0.7,
        .steps = &[_]@TypeOf(Plan).Step{},
        .rollback = null,
    };

    const result = Result{
        .success = true,
        .@"error" = null,
        .timing = .{
            .start_ns = 1234567890,
            .end_ns = 1234567990,
            .duration_ms = 100,
        },
        .output = null,
        .new_senses = .{},
    };

    const episode = try recordEpisode(allocator, context, plan, result, .success);

    try std.testing.expect(episode.timestamp_ns == 1234567890);
    try std.testing.expect(episode.source == .lotus_cycle);
